    19→pub fn create_tray<R: Runtime>(app: &AppHandle<R>) -> tauri::Result<()> {
    20→    let toggle_i = MenuItem::with_id(app, "toggle", "Disable", true, None::<&str>)?;
    21→    let separator0 = PredefinedMenuItem::separator(app)?;
    22→    let resume_i = MenuItem::with_id(app, "resume", "Resume", false, None::<&str>)?;
    23→    let pause_30_i = MenuItem::with_id(app, "pause_30", "Pause 30 min", true, None::<&str>)?;
    24→    let pause_60_i = MenuItem::with_id(app, "pause_60", "Pause 1 hour", true, None::<&str>)?;
    25→    let separator1 = PredefinedMenuItem::separator(app)?;
    26→    let settings_i = MenuItem::with_id(app, "settings", "Settings...", true, None::<&str>)?;
    27→    let separator2 = PredefinedMenuItem::separator(app)?;
    28→    let quit_i = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
    29→
    30→    let menu = Menu::with_items(
    31→        app,
    32→        &[
    33→            &toggle_i,
    34→            &separator0,
    35→            &resume_i,
    36→            &pause_30_i,
    37→            &pause_60_i,
    38→            &separator1,
    39→            &settings_i,
    40→            &separator2,
    41→            &quit_i,
    42→        ],
    43→    )?;
    44→
    45→    let icon = Image::from_bytes(include_bytes!("../icons/tray-active.png"))
    46→        .expect("Failed to load tray icon");
    47→
    48→    // Show "DEV" label next to icon in debug builds to distinguish from production
    49→    #[cfg(debug_assertions)]
    50→    let tray_title = Some("DEV");
    51→    #[cfg(not(debug_assertions))]
    52→    let tray_title: Option<&str> = None;
    53→
    54→    let mut builder = TrayIconBuilder::with_id("main")
    55→        .icon(icon)
    56→        .icon_as_template(false)
    57→        .menu(&menu)
    58→        .show_menu_on_left_click(true);
    59→
    60→    // Set title only in dev mode (shows text next to icon on macOS)
    61→    if let Some(title) = tray_title {
    62→        builder = builder.title(title);
    63→    }
    64→
    65→    let _ = builder
    66→        .on_menu_event(move |app, event| {
    67→            // Helper to update pause-related menu items
    68→            let update_pause_menu = |is_paused: bool, remaining: Option<u32>| {
    69→                if is_paused {
    70→                    if let Some(mins) = remaining {
    71→                        let _ = resume_i.set_text(&format!("Resume ({} min left)", mins));
    72→                    } else {
    73→                        let _ = resume_i.set_text("Resume");
    74→                    }
    75→                    let _ = resume_i.set_enabled(true);
    76→                    let _ = pause_30_i.set_enabled(false);
    77→                    let _ = pause_60_i.set_enabled(false);
    78→                } else {
    79→                    let _ = resume_i.set_text("Resume");
    80→                    let _ = resume_i.set_enabled(false);
    81→                    let _ = pause_30_i.set_enabled(true);
    82→                    let _ = pause_60_i.set_enabled(true);
    83→                }
    84→            };
    85→
    86→            // Update menu state when menu event occurs
    87→            {
    88→                let state = app.state::<crate::AppState>();
    89→                let keeper = state.keeper.lock().unwrap();
    90→                let is_running = keeper.is_running();
    91→
    92→                // Update toggle text
    93→                if is_running {
    94→                    let _ = toggle_i.set_text("Disable");
    95→                } else {
    96→                    let _ = toggle_i.set_text("Enable");
    97→                }
    98→
    99→                // Update tray icon to reflect current state
   100→                if let Some(tray) = app.tray_by_id("main") {
   101→                    update_tray_icon(&tray, is_running);
   102→                }
   103→
   104→                // Update pause status
   105→                update_pause_menu(keeper.is_paused(), keeper.pause_remaining_minutes());
   106→            }
   107→
   108→            match event.id.as_ref() {
   109→                "toggle" => {
   110→                    let state = app.state::<crate::AppState>();
   111→                    let mut keeper = state.keeper.lock().unwrap();
   112→                    let is_running = keeper.is_running();
   113→                    if is_running {
   114→                        keeper.stop();
   115→                        let _ = toggle_i.set_text("Enable");
   116→                    } else {
   117→                        keeper.start();
   118→                        let _ = toggle_i.set_text("Disable");
   119→                    }
   120→                    // Update tray icon to reflect the new state
   121→                    if let Some(tray) = app.tray_by_id("main") {
   122→                        update_tray_icon(&tray, !is_running);
   123→                    }
   124→                }
   125→                "resume" => {
   126→                    let state = app.state::<crate::AppState>();
   127→                    let mut keeper = state.keeper.lock().unwrap();
   128→                    keeper.resume();
   129→                    update_pause_menu(false, None);
   130→                }
   131→                "pause_30" => {
   132→                    let state = app.state::<crate::AppState>();
   133→                    let mut keeper = state.keeper.lock().unwrap();
   134→                    keeper.pause(30);
   135→                    update_pause_menu(true, Some(30));
   136→                }
   137→                "pause_60" => {
   138→                    let state = app.state::<crate::AppState>();
   139→                    let mut keeper = state.keeper.lock().unwrap();
   140→                    keeper.pause(60);
   141→                    update_pause_menu(true, Some(60));
   142→                }
   143→                "settings" => {
   144→                    if let Some(window) = app.get_webview_window("main") {
   145→                        let _ = window.show();
   146→                        let _ = window.set_focus();
   147→                    }
   148→                }
   149→                "quit" => {
   150→                    let state = app.state::<crate::AppState>();
   151→                    let mut keeper = state.keeper.lock().unwrap();
   152→                    keeper.stop();
   153→                    drop(keeper);
   154→                    crate::request_exit();
   155→                    app.exit(0);
   156→                }
   157→                _ => {}
   158→            }
   159→        })
   160→        .build(app)?;
   161→
   162→    Ok(())
   163→}
