    38→    pub fn start(&mut self) {
    39→        if self.running.load(Ordering::SeqCst) {
    40→            return;
    41→        }
    42→
    43→        self.running.store(true, Ordering::SeqCst);
    44→        let running = self.running.clone();
    45→        let paused_until = self.paused_until.clone();
    46→        let config = self.config.clone();
    47→
    48→        thread::spawn(move || {
    49→            let mut mouse = match HumanMouse::new() {
    50→                Ok(m) => m,
    51→                Err(e) => {
    52→                    eprintln!("Failed to initialize mouse: {}", e);
    53→                    running.store(false, Ordering::SeqCst);
    54→                    return;
    55→                }
    56→            };
    57→
    58→            let mut enigo = match Enigo::new(&Settings::default()) {
    59→                Ok(e) => e,
