    97→                    let break_mins = rng.gen_range(
    98→                        config.natural_breaks.duration_min..=config.natural_breaks.duration_max,
    99→                    );
   100→                    println!("Taking a natural break for {} minutes", break_mins);
   101→                    thread::sleep(Duration::from_secs(break_mins as u64 * 60));
   102→                    continue;
   103→                }
   104→
   105→                // Wait for user to be idle before performing activity
   106→                if !input_monitor::is_user_idle(config.idle_threshold_sec) {
   107→                    let idle_for = input_monitor::seconds_since_last_input();
   108→                    println!(
   109→                        "[Presence] User active (idle {}s, threshold {}s), skipping activity",
   110→                        idle_for, config.idle_threshold_sec
   111→                    );
   112→                    thread::sleep(Duration::from_secs(1));
   113→                    continue;
   114→                }
   115→
   116→                // Perform activity
   117→                let result = match config.mode.as_str() {
   118→                    "mouse" => mouse.human_move(config.human_like),
   119→                    "keyboard" => jiggle_keyboard(&mut enigo),
   120→                    "both" => {
   121→                        if rng.gen_bool(0.5) {
   122→                            mouse.human_move(config.human_like)
   123→                        } else {
   124→                            jiggle_keyboard(&mut enigo)
   125→                        }
   126→                    }
   127→                    _ => mouse.human_move(config.human_like),
   128→                };
   129→
   130→                if let Err(e) = result {
   131→                    eprintln!("Activity failed: {}", e);
   132→                }
   133→
   134→                // Sleep until next activity
